			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}
			if n.Data == "meta" && description == "" {
				for i := 0; i < len(n.Attr); i++ {
					attr := n.Attr[i]
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						for j := 0; j < len(n.Attr); j++ {
							if n.Attr[j].Key == "content" {
								description = n.Attr[j].Val
								return
							}
						}
					}
					if attr.Key == "property" && strings.ToLower(attr.Val) == "og:description" && description == "" {
						for j := 0; j < len(n.Attr); j++ {
							if n.Attr[j].Key == "content" {
								description = n.Attr[j].Val
								return
							}
						}
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	// Clean up whitespace
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

// getText extracts text content from an HTML node.
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

