	tokenizer := html.NewTokenizer(strings.NewReader(string(body)))
	inTitle := false
	titleBuilder := strings.Builder{}
	description = ""

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return
		case html.StartTagToken:
			tag := tokenizer.Token()
			if tag.Data == "title" {
				inTitle = true
				titleBuilder.Reset()
			} else if tag.Data == "meta" {
				// Look for description meta tag
				for _, attr := range tag.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						// Found description meta tag, now look for content attribute
						for _, attr2 := range tag.Attr {
							if attr2.Key == "content" {
								description = attr2.Val
								break
							}
						}
						break
					}
					// Also check for og:description
					if attr.Key == "property" && attr.Val == "og:description" {
						for _, attr2 := range tag.Attr {
							if attr2.Key == "content" {
								if description == "" {
									description = attr2.Val
								}
								break
							}
						}
						break
					}
				}
			}
		case html.EndTagToken:
			tag := tokenizer.Token()
			if tag.Data == "title" {
				inTitle = false
				title = strings.TrimSpace(titleBuilder.String())
			}
		case html.TextToken:
			if inTitle {
				titleBuilder.WriteString(tokenizer.Token().Data)
			}
		}
	}
}

