package main

import (
	"encoding/json"
	"net"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// URLPreviewRequest represents the expected JSON request body
type URLPreviewRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// isPrivateIP checks if an IP address is in a private network range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
}

// safeDialer creates a dial function that prevents SSRF by blocking private IPs
func safeDialer(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		// If SplitHostPort fails, addr might not have a port, so treat entire addr as host
		host = addr
	}
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fasthttp.ErrNoFreeConns // Using this as a generic connection error; could create custom error
		}
	}
	return fasthttp.DialDualStackTimeout(addr, 10*time.Second)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Create a fasthttp client with SSRF protection and timeout
	client := &fasthttp.Client{
		Dial:                  safeDialer,
		ReadTimeout:           10 * time.Second,
		WriteTimeout:          10 * time.Second,
		MaxIdleConnDuration:   10 * time.Second,
		MaxConnDuration:       10 * time.Second,
		MaxConnsPerHost:       100,
		MaxIdemponentCallAttempts: 0, // Disable retries to prevent SSRF bypass
	}

	// Create a request and response for the URL fetch
	urlReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(urlReq)
	urlResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(urlResp)

	urlReq.SetRequestURI(req.URL)
	urlReq.Header.SetMethod("GET")

	// Fetch the URL with limited redirects
	err := client.DoRedirects(urlReq, urlResp, 3) // Reduced from 10 to 3 to prevent excessive redirects
	if err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusInternalServerError)
		return
	}

	if urlResp.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := extractTitleAndDescription(urlResp.Body())

	// Create and return the response
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	respBytes, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Failed to create response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetBody(respBytes)
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	title := ""
	description := ""

	// Parse the HTML
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return title, description
	}

	// Walk through the HTML nodes
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && title == "" {
			title = getText(n)
		}
		if n.Type == html.ElementNode && n.Data == "meta" && description == "" {
			for i := 0; i < len(n.Attr); i++ {
				attr := n.Attr[i]
				if (attr.Key == "name" && attr.Val == "description") ||
					(attr.Key == "property" && attr.Val == "og:description") {
					// Look for content attribute
					for j := 0; j < len(n.Attr); j++ {
						if n.Attr[j].Key == "content" {
							description = n.Attr[j].Val
							break
						}
					}
					break
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

