// extractTitleAndDescription parses HTML and extracts the title and meta description.
func extractTitleAndDescription(body []byte) (title, description string) {
	tokenizer := html.NewTokenizer(strings.NewReader(string(body)))
	isInTitle := false
	titleBuilder := strings.Builder{}
	metaDescription := ""

	for {
