					} else if attr.Key == "content" {
						hasContent = true
						contentVal2 = attr.Val
					}
				}
				if hasProperty && hasContent && metaDescription == "" {
					metaDescription = contentVal2
				}
			}
		case html.EndTagToken:
			tag := tokenizer.Token()
			if tag.Data == "title" {
				isInTitle = false
			}
		case html.TextToken:
			if isInTitle {
				titleBuilder.WriteString(strings.TrimSpace(tokenizer.Token().Data))
			}
		}
	}
