func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse the URL to validate and extract host
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
		return
	}

	// Check if the host is a private/internal IP address to prevent SSRF
	host := parsedURL.Host
	if isPrivateIP(host) {
		ctx.Error("Access to private/internal addresses is not allowed", fasthttp.StatusBadRequest)
		return
	}

	// Create a fasthttp client with security configurations
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		// Set timeouts to prevent hanging requests
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		MaxConnsPerHost: 100,
		// Prevent following redirects to internal addresses
		MaxRedirectsCount: 5,
	}

	// Create a request and response for the URL fetch
	reqHTTP := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqHTTP)
	respHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respHTTP)

	reqHTTP.SetRequestURI(req.URL)
	reqHTTP.Header.SetMethod("GET")
	// Set a reasonable user agent
	reqHTTP.Header.SetUserAgent("URLPreviewBot/1.0")

	// Fetch the URL with limited redirects
	if err := client.DoRedirects(reqHTTP, respHTTP, 5); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusInternalServerError)
		return
	}

	// Check if the response status is OK
	if respHTTP.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Failed to fetch URL: non-200 status", fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTMLForPreview(respHTTP.Body())

	// Create response
	result := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	// Return JSON response
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(result); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// isPrivateIP checks if the given host resolves to a private/internal IP address
func isPrivateIP(host string) bool {
	// Remove port if present
	if idx := strings.IndexByte(host, ':'); idx != -1 {
		host = host[:idx]
	}

	// Try to resolve the host
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve, be safe and assume it might be private
		// But actually, we should allow public DNS names that might fail temporarily
		// So we'll only check if it's an IP address directly
		if ip := net.ParseIP(host); ip != nil {
			return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
		}
		return false
	}

	// Check if any of the resolved IPs are private
	for _, ip := range ips {
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}
	return false
}

// parseHTMLForPreview extracts the title and meta description from HTML content
func parseHTMLForPreview(body []byte) (title, description string) {
	reader := strings.NewReader(string(body))
	tokenizer := html.NewTokenizer(reader)

	// State variables
	inTitle := false
	titleBuilder := strings.Builder{}
	description = ""

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of document or error
			return titleBuilder.String(), description
		case html.StartTagToken:
			tag := tokenizer.Token()
			tagName := strings.ToLower(tag.Data)
			if tagName == "title" {
				inTitle = true
				titleBuilder.Reset()
			} else if tagName == "meta" {
				// Look for description meta tag
				hasDescription := false
				contentValue := ""
				for _, attr := range tag.Attr {
					if strings.ToLower(attr.Key) == "name" && strings.ToLower(attr.Val) == "description" {
						hasDescription = true
					}
					if strings.ToLower(attr.Key) == "content" {
						contentValue = attr.Val
					}
				}
				if hasDescription && description == "" {
					description = contentValue
				}
			}
		case html.EndTagToken:
			tag := tokenizer.Token()
			tagName := strings.ToLower(tag.Data)
			if tagName == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle {
				titleBuilder.WriteString(strings.TrimSpace(tokenizer.Token().Data))
			}
		}
	}
}

