			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// isPrivateIP checks if an IP address is in a private network range.
func isPrivateIP(ip net.IP) bool {
	privateBlocks := []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // IPv4 RFC1918
		"172.16.0.0/12",  // IPv4 RFC1918
		"192.168.0.0/16", // IPv4 RFC1918
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 unique local addr (RFC4193)
		"fe80::/10",      // IPv6 link-local
	}

	for _, block := range privateBlocks {
		_, ipNet, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && title == "" {
			title = getText(n)
		}
		if n.Type == html.ElementNode && n.Data == "meta" && description == "" {
			for i := 0; i < len(n.Attr); i++ {
				attr := n.Attr[i]
				if (attr.Key == "name" && attr.Val == "description") ||
					(attr.Key == "property" && attr.Val == "og:description") {
