			f(c)
		}
	}
	f(doc)

	// If no meta description found, try to get a fallback from the body content
	if description == "" {
		var bodyText string
		var getBodyText func(*html.Node)
		getBodyText = func(n *html.Node) {
			if n.Type == html.ElementNode && n.Data == "body" {
				bodyText = getText(n)
				// Limit the length of the description
				if len(bodyText) > 200 {
					bodyText = bodyText[:200]
					// Try to cut at a word boundary
					lastSpace := strings.LastIndex(bodyText, " ")
					if lastSpace > 0 {
						bodyText = bodyText[:lastSpace]
					}
					bodyText += "..."
				}
				description = bodyText
			}
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				getBodyText(c)
			}
		}
		getBodyText(doc)
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// getText extracts all text content from an HTML node.
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

