// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and prevent SSRF
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prevent SSRF by checking if the host is a private IP address
	if isPrivateIP(parsedURL.Hostname()) {
		ctx.Error("URL points to a private IP address", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout and security settings
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Parse the address to get host and port
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, the addr might not have a port
				host = addr
			}
			// Check if the resolved IP is private
			if isPrivateIP(host) {
				return nil, fmt.Errorf("private IP addresses are not allowed")
			}
			return fasthttp.DialDualStack(addr)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		// Disable redirects to handle them manually for better security control
		MaxRedirectsCount: 0,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Handle redirects manually to validate each redirect URL
	maxRedirectCounts := 10
	currentURL := targetURL
	for i := 0; i < maxRedirectCounts; i++ {
		freq.SetRequestURI(currentURL)
		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()
		if statusCode == fasthttp.StatusOK {
			break
		}

		if statusCode == fasthttp.StatusMovedPermanently ||
			statusCode == fasthttp.StatusFound ||
			statusCode == fasthttp.StatusSeeOther ||
			statusCode == fasthttp.StatusTemporaryRedirect ||
			statusCode == fasthttp.StatusPermanentRedirect {

			location := string(res.Header.Peek("Location"))
			if location == "" {
				ctx.Error("Redirect without Location header", fasthttp.StatusBadGateway)
				return
			}

			// Resolve relative URLs
			redirectURL, err := url.Parse(location)
			if err != nil {
				ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
				return
			}
			baseURL, err := url.Parse(currentURL)
			if err != nil {
				ctx.Error("Invalid base URL", fasthttp.StatusBadGateway)
				return
			}
			currentURL = baseURL.ResolveReference(redirectURL).String()

			// Validate the redirect URL
			parsedRedirectURL, err := url.ParseRequestURI(currentURL)
			if err != nil {
				ctx.Error("Invalid redirect URL format", fasthttp.StatusBadRequest)
				return
			}

			if parsedRedirectURL.Scheme != "http" && parsedRedirectURL.Scheme != "https" {
				ctx.Error("Redirect URL must use http or https scheme", fasthttp.StatusBadRequest)
				return
			}

			if isPrivateIP(parsedRedirectURL.Hostname()) {
				ctx.Error("Redirect URL points to a private IP address", fasthttp.StatusBadRequest)
				return
			}

			// Reset request for next iteration
			freq.Reset()
			res.Reset()
			continue
		} else {
			ctx.Error(fmt.Sprintf("Unexpected status code: %d", statusCode), fasthttp.StatusBadGateway)
			return
		}
	}

	if len(res.Body()) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isPrivateIP checks if the given host is a private IP address.
func isPrivateIP(host string) bool {
	// Try to parse as IP address directly
	if ip := net.ParseIP(host); ip != nil {
		return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	// If it's a hostname, resolve it and check the IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve, assume it's not private to avoid blocking legitimate domains
		return false
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}
	return false
}

