// extractTitleAndDescription parses HTML and extracts title and meta description
func extractTitleAndDescription(body []byte) (string, string) {
	reader := strings.NewReader(string(body))
	tokenizer := html.NewTokenizer(reader)

	var title string
	var description string
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			return strings.TrimSpace(title), strings.TrimSpace(description)
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.DataAtom.String()

			if tagName == "title" {
				inTitle = true
			} else if tagName == "meta" {
				// Look for meta description
				for _, attr := range token.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						// Found description meta tag, now look for content attribute
						for _, attr2 := range token.Attr {
							if attr2.Key == "content" {
								description = attr2.Val
								break
							}
						}
						break
					} else if attr.Key == "property" && strings.ToLower(attr.Val) == "og:description" {
						// Also check for Open Graph description
						for _, attr2 := range token.Attr {
							if attr2.Key == "content" {
								if description == "" {
									description = attr2.Val
								}
								break
							}
						}
						break
					}
				}
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if token.DataAtom.String() == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle && title == "" {
				title = tokenizer.Token().Data
			}
		}
	}
}

