		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
		// Security: Set a reasonable size limit to prevent memory exhaustion
		freq.Header.Set("Accept-Encoding", "gzip")

