			return
		}

		bodyBytes := res.Body()
		// Security: Limit response body size to prevent memory exhaustion
		maxBodySize := 10 * 1024 * 1024 // 10MB
		if len(bodyBytes) > maxBodySize {
			ctx.Error("Response body too large", fasthttp.StatusRequestEntityTooLarge)
