// isPrivateIP checks if the given hostname resolves to a private IP address
func isPrivateIP(hostname string) bool {
	// Parse as IP first
	if ip := net.ParseIP(hostname); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	// If it's a hostname, resolve it and check
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return false
	}

	for _, ip := range ips {
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}
	return false
}

// parseHTMLPreview extracts title and description from HTML content
func parseHTMLPreview(htmlContent []byte) (string, string) {
	// Simple HTML parsing without external dependencies
	title := ""
	description := ""

	// Convert to string for easier processing
	content := string(htmlContent)

	// Find title tag
	titleStart := strings.Index(strings.ToLower(content), "<title>")
	if titleStart != -1 {
		titleEnd := strings.Index(strings.ToLower(content[titleStart:]), "</title>")
		if titleEnd != -1 {
			titleTagContent := content[titleStart+7 : titleStart+titleEnd]
			title = strings.TrimSpace(titleTagContent)
		}
	}

	// Find meta description tag
	descLower := strings.ToLower(content)
	descStart := strings.Index(descLower, "name=\"description\"")
	if descStart == -1 {
		descStart = strings.Index(descLower, "name='description'")
	}
	if descStart != -1 {
		// Look for content attribute after name="description"
		contentStart := strings.Index(content[descStart:], "content=")
		if contentStart != -1 {
			contentStart += descStart + 8 // +8 for "content="
			// Handle both single and double quotes
			quote := byte('"')
			if contentStart < len(content) && content[contentStart] == '\'' {
				quote = '\''
			}
			if contentStart < len(content) && (content[contentStart] == '"' || content[contentStart] == '\'') {
				contentStart++
				contentEnd := strings.Index(content[contentStart:], string(quote))
				if contentEnd != -1 {
					description = strings.TrimSpace(content[contentStart : contentStart+contentEnd])
				}
			}
		}
	}

	return title, description
}

