// extractTitleAndDescription parses HTML and extracts title and meta description
func extractTitleAndDescription(body []byte) (string, string) {
	reader := strings.NewReader(string(body))
	tokenizer := html.NewTokenizer(reader)

	var title string
	var description string
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.DataAtom.String()

			if tagName == "title" {
				inTitle = true
			} else if tagName == "meta" {
				// Look for description meta tag
				for _, attr := range token.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						// Found description meta tag, get the content
						for _, attr2 := range token.Attr {
							if attr2.Key == "content" {
