								}
								break
							}
						}
						break
					}
				}
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if token.DataAtom.String() == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle && title == "" {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}
	}
}

