		}
	}

	// Validate that the port is a standard HTTP/HTTPS port
	if port != "80" && port != "443" && port != "8080" && port != "8443" {
		ctx.Error("Only standard HTTP/HTTPS ports are allowed", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout and security settings
	client := &fasthttp.Client{
		Dial:                    fasthttp.DialDualStack,
		ReadTimeout:             10 * time.Second,
		WriteTimeout:            10 * time.Second,
		MaxIdleConnDuration:     10 * time.Second,
		MaxConnsPerHost:         10,
		DisablePathNormalizing:  false,
		MaxResponseBodySize:     10 * 1024 * 1024, // 10MB limit
	}

