	"golang.org/x/net/html"
)

// URLPreviewRequest represents the expected JSON request body
type URLPreviewRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Create a fasthttp client with the required settings
	client := &fasthttp.Client{
		Dial:                  fasthttp.DialDualStack,
		MaxIdleConnDuration:   3 * time.Second,
		ReadTimeout:           3 * time.Second,
		WriteTimeout:          3 * time.Second,
		MaxResponseBodySize:   10 * 1024 * 1024, // 10MB max response size
	}

	// Create a request with the provided URL
	request := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(request)
	request.SetRequestURI(req.URL)
	request.Header.SetMethod("GET")

	// Create a response to hold the result
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(response)

	// Perform the request with redirects (max 10 redirects)
	if err := client.DoRedirects(request, response, 10); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// Check if the status code is OK
	if response.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := extractTitleAndDescription(response.Body())

	// Create the response JSON
	result := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	// Marshal the response to JSON
	jsonData, err := json.Marshal(result)
	if err != nil {
		ctx.Error("Internal server error", fasthttp.StatusInternalServerError)
		return
	}

	// Set the content type and write the response
	ctx.SetContentType("application/json")
	ctx.SetBody(jsonData)
}

// extractTitleAndDescription parses HTML and extracts the title and meta description
func extractTitleAndDescription(body []byte) (string, string) {
	title := ""
	description := ""

	// Parse the HTML
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return title, description
	}

	// Walk through the HTML nodes
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}
			if n.Data == "meta" {
				description = getMetaDescription(n, description)
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

// getText extracts text content from an HTML node
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

// getMetaDescription checks if a meta tag contains a description
func getMetaDescription(n *html.Node, currentDesc string) string {
	if currentDesc != "" {
		return currentDesc
	}

	var name, content string
	for _, attr := range n.Attr {
		if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
			name = attr.Val
		}
		if attr.Key == "content" {
			content = attr.Val
		}
	}

	if name != "" && content != "" {
		return content
	}

	// Also check for og:description (Open Graph)
	name = ""
	content = ""
	for _, attr := range n.Attr {
		if attr.Key == "property" && attr.Val == "og:description" {
			name = attr.Val
		}
		if attr.Key == "content" {
			content = attr.Val
		}
	}

	if name != "" && content != "" {
		return content
	}

	return currentDesc
}

