package main

import (
	"encoding/json"
	"errors"
	"strconv"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// URLPreviewRequest represents the expected JSON request body
type URLPreviewRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response
type URLPreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := URLPreviewResponse{Error: "Invalid JSON request body"}
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(response)
		return
	}

	if strings.TrimSpace(req.URL) == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := URLPreviewResponse{Error: "URL is required"}
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Initialize fasthttp client with required settings
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Create a request for the provided URL
	request := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(request)
	request.SetRequestURI(req.URL)
	request.Header.SetMethod("GET")

	// Perform the request with redirects
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(response)
	if err := client.DoRedirects(request, response, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp := URLPreviewResponse{Error: "Failed to fetch URL: " + err.Error()}
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Check if the response status is OK
	if response.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp := URLPreviewResponse{Error: "Received non-200 status code: " + strconv.Itoa(response.StatusCode())}
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTMLForPreview(response.Body())

	// Prepare and send the JSON response
	result := URLPreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.Response.Header.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(result)
}

// parseHTMLForPreview extracts the title and meta description from HTML content
func parseHTMLForPreview(body []byte) (title, description string) {
	reader := strings.NewReader(string(body))
	tokenizer := html.NewTokenizer(reader)

	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of document or error
			return
		case html.StartTagToken, html.EndTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagStr := string(tagName)

			if tt == html.StartTagToken {
				if tagStr == "title" {
					inTitle = true
				} else if tagStr == "meta" {
					// Look for meta description
					attr := make(map[string]string)
					for hasAttr {
						key, val, more := tokenizer.TagAttr()
						attr[string(key)] = string(val)
						hasAttr = more
					}
					if name, ok := attr["name"]; ok && strings.ToLower(name) == "description" {
						if desc, ok := attr["content"]; ok && description == "" {
							description = desc
						}
					}
					// Also check for Open Graph description
					if prop, ok := attr["property"]; ok && prop == "og:description" {
						if desc, ok := attr["content"]; ok && description == "" {
							description = desc
						}
					}
				}
			} else if tt == html.EndTagToken {
				if tagStr == "title" {
					inTitle = false
				}
			}
		case html.TextToken:
			if inTitle && title == "" {
				title = strings.TrimSpace(string(tokenizer.Text()))
			}
		}
	}
}

