		host := parsedURL.Hostname()
		if ip := net.ParseIP(host); ip != nil {
			if !ip.IsGlobalUnicast() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() {
				ctx.Error("URL must not point to private or reserved IP addresses", fasthttp.StatusBadRequest)
				return
			}
		}

		// Use fasthttp.Client to fetch with timeout
		client := &fasthttp.Client{
			Dial:                fasthttp.DialDualStack,
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 10 * time.Second,
			MaxConnsPerHost:     10,
			// Disable redirects by setting MaxRedirectsCount to 0
