// extractTitleAndDescription parses HTML and extracts title and meta description
func extractTitleAndDescription(body []byte) (string, string) {
	title := ""
	description := ""

	// Parse the HTML
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return title, description
	}

	// Walk through the HTML nodes
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" && description == "" {
					description = content
				}

				// Also check for og:description
				if description == "" {
					var property, content string
					for _, attr := range n.Attr {
						if attr.Key == "property" && attr.Val == "og:description" {
							property = attr.Val
						}
						if attr.Key == "content" {
							content = attr.Val
						}
					}
					if property != "" && content != "" {
						description = content
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
