// isPrivateIP checks if an IP address is in private ranges (RFC 1918 and others).
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	privateBlocks := []string{
		"0.0.0.0/8",
		"10.0.0.0/8",
		"100.64.0.0/10",
		"127.0.0.0/8",
		"169.254.0.0/16",
		"172.16.0.0/12",
		"192.0.0.0/24",
		"192.0.2.0/24",
		"192.168.0.0/16",
		"198.18.0.0/15",
		"198.51.100.0/24",
		"203.0.113.0/24",
		"224.0.0.0/4",
		"::1/128",
		"fc00::/7",
		"fe80::/10",
	}
	for _, block := range privateBlocks {
		_, ipNet, err := net.ParseCIDR(block)
		if err == nil && ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

// FetchURLPreview handles POST requests to fetch and parse URL previews.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if ctx.IsPost() {
		var req URLPreviewRequest
		if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		if req.URL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Ensure the URL has a scheme
		urlToFetch := req.URL
		if !strings.HasPrefix(urlToFetch, "http://") && !strings.HasPrefix(urlToFetch, "https://") {
			urlToFetch = "https://" + urlToFetch
		}

		// Parse URL to extract host
		parsedURL, err := fasthttp.ParseURI(urlToFetch)
		if err != nil {
			response := URLPreviewResponse{Error: "Invalid URL format"}
			ctx.SetContentType("application/json")
			jsonBytes, _ := json.Marshal(response)
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
			ctx.Write(jsonBytes)
			return
		}

		host := string(parsedURL.Host())
		// Remove port if present
		if i := strings.IndexByte(host, ':'); i >= 0 {
			host = host[:i]
		}

		// Resolve hostname to IP addresses
		ips, err := net.LookupIP(host)
		if err != nil {
			response := URLPreviewResponse{Error: "Failed to resolve hostname"}
			ctx.SetContentType("application/json")
			jsonBytes, _ := json.Marshal(response)
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
			ctx.Write(jsonBytes)
			return
		}

		// Check if any resolved IP is private or loopback
		for _, ip := range ips {
			if isPrivateIP(ip) {
				response := URLPreviewResponse{Error: "Access to private IP addresses is not allowed"}
				ctx.SetContentType("application/json")
				jsonBytes, _ := json.Marshal(response)
				ctx.SetStatusCode(fasthttp.StatusForbidden)
				ctx.Write(jsonBytes)
				return
			}
		}

		// Initialize client with required settings
		client := &fasthttp.Client{
			Dial: fasthttp.DialDualStack,
		}

		reqFastHTTP := fasthttp.AcquireRequest()
		respFastHTTP := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(reqFastHTTP)
		defer fasthttp.ReleaseResponse(respFastHTTP)

		reqFastHTTP.SetRequestURI(urlToFetch)
		reqFastHTTP.Header.SetMethod("GET")

		// Use DoRedirects to follow redirects (max 16 redirects as per default)
		if err := client.DoRedirects(reqFastHTTP, respFastHTTP, 16); err != nil {
			response := URLPreviewResponse{Error: "Failed to fetch URL: " + err.Error()}
			ctx.SetContentType("application/json")
			jsonBytes, _ := json.Marshal(response)
			ctx.SetStatusCode(fasthttp.StatusInternalServerError)
			ctx.Write(jsonBytes)
			return
		}

		if respFastHTTP.StatusCode() != fasthttp.StatusOK {
			response := URLPreviewResponse{Error: "Received non-200 status code: " + strconv.Itoa(respFastHTTP.StatusCode())}
			ctx.SetContentType("application/json")
			jsonBytes, _ := json.Marshal(response)
			ctx.SetStatusCode(fasthttp.StatusBadGateway)
			ctx.Write(jsonBytes)
			return
		}

		// Parse HTML to extract title and meta description
		title, description := parseHTMLForPreview(respFastHTTP.Body())

		response := URLPreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json")
		jsonBytes, _ := json.Marshal(response)
		ctx.SetStatusCode(fasthttp.StatusOK)
		ctx.Write(jsonBytes)
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLForPreview extracts the title and meta description from HTML content.
func parseHTMLForPreview(body []byte) (title, description string) {
	reader := strings.NewReader(string(body))
	tokenizer := html.NewTokenizer(reader)

	inTitle := false
	for {
		tt := tokenizer.Next()

		switch tt {
		case html.ErrorToken:
			// End of document or error
			return
		case html.StartTagToken:
			tag := tokenizer.Token()
			switch tag.Data {
			case "title":
				inTitle = true
			case "meta":
				// Look for description meta tag
				if description != "" {
					continue // already found
				}
				var name, content string
				for _, attr := range tag.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		case html.EndTagToken:
			tag := tokenizer.Token()
			if tag.Data == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle && title == "" {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}
	}
}

